var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"으으… 근육통이….","JPN":"うう……筋肉痛が……","ENG":"Ugh... Muscles cramps...","TWN":"唔…肌肉酸痛…"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"성녀는 체력이 많이 부족한 것 같습니다.","JPN":"聖女は体力がだいぶ足りないようですね。","ENG":"You seem to lack a good deal of stamina.","TWN":"聖女體力真差。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"지팡이의 힘에 기대는 것은 바람직한 행위가 아닙니다, 루크레시아.","JPN":"杖の力に依存することは望ましい行為ではありません、ルクレシア。","ENG":"You mustn't always rely on the power of your staff, Lucrecia.","TWN":"還要拄著杖，這樣就不是完全靠自己的力量，露可蕾西亞。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 이상한 겁니다. 가파른 산을 뛰어다녔는데 그리 멀쩡하다니요.","JPN":"あなたがおかしいのです。険しい山を走り回ったのに何ともないなんて。","ENG":"I'm not the one who's weird. How are you still so tireless, after all that trekking?","TWN":"你才奇怪，跑上這麼陡的山，居然還這麼有精神。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"깃발까지 들고 어떻게 그럴 수가 있는 건가요?","JPN":"旗まで持っているのに、どうしてそんなことが可能なのですか？","ENG":"You've even been holding the banner up.","TWN":"而且還拿著旗幟，這怎麼可能？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"확실히 오늘은 몸상태가 좋은 편이군요.","JPN":"確かに、今日は体の具合がいい方ですね。","ENG":"I do feel quite spirited today.","TWN":"今天的狀態的確很好。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"방금 전 싸움에서도 구원자보다 더 많은 괴수를 쓰러트렸을 정도입니다.","JPN":"先ほどの戦いでも、救世主より多くの怪獣を倒したくらいです。","ENG":"I even vanquished more monsters than the Savior in the fight earlier.","TWN":"在剛才的戰鬥中，我擊殺的怪獸數量還比救贖者大人大人多呢。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯 님이요?","JPN":"シャーロット様が？","ENG":"You did, Carlota?","TWN":"真的嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"네. 제가 스물 여섯 마리의 괴수를 해치운 반면, 구원자는 스물 두 마리의 괴수만을 해치웠습니다.","JPN":"はい。私は26匹の怪獣を倒しましたが、救世主は22匹でした。","ENG":"Indeed. I eliminated 26 monsters, while the Savior only eliminated 22.","TWN":"真的。我一共擊殺26隻怪獸，救贖者大人大人只擊殺22隻。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원자 또한 자신의 패배를 인정했고요.","JPN":"救世主も自分の負けを認めました。","ENG":"The Savior has also admitted his defeat.","TWN":"救贖者大人大人也有承認自己的失敗。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이상하네요. 구원자 님 방향으로 어림잡아 오십은 갔을 텐데요.","JPN":"おかしいですね。救世主様の方向にざっと50匹は向かっていたはずですけど。","ENG":"Odd. I saw around 50 go toward the Savior.","TWN":"真奇怪，照我看到的，救贖者大人大人應該至少擊殺50隻才對。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"날 속였군. 구원자.","JPN":"私を騙したな、救世主。","ENG":"The Savior fooled me.","TWN":"你騙我，救贖者大人大人。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"매번 구원자님께 깨져 놓고 잘도 이겼다는 생각을 하셨군요.","JPN":"毎回救世主様に負けておいて、よく勝ったと思えましたね。","ENG":"He always beats you. Why did you think it would be different this time?","TWN":"你每次都輸給救贖者大人大人，怎麼還會覺得自己有可能贏？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그나저나 축제. 인가요….","JPN":"それより、お祭り、ですか……","ENG":"Anyway, about the festival...","TWN":"說到慶典…"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"신기한 풍습입니다. 순정한 남녀 한 쌍을 선별해 풍요를 권장하는 신께 춤을 올린다니.","JPN":"不思議な風習です。無垢な男女を選抜し、豊穣を司る神に踊りを捧げるとは。","ENG":"It's an interesting tradition, to say the least. Selecting a chaste couple to dance for the god of prosperity.","TWN":"還真是特別的習俗。選出一對純真的男女，向神跳豐收舞。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님은 사람이 너무 좋으십니다. 직접 나서실 필요까지는 없는 일이었어요.","JPN":"救世主様は人が良すぎます。自らがされる必要などありませんのに。","ENG":"The Savior can be too kind-hearted sometimes. He didn't have to step in.","TWN":"救贖者大人大人人真的太好，根本不需要他親自出馬的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원자가 신경 쓰이십니까?","JPN":"救世主が気になりますか？","ENG":"Does the Savior concern you?","TWN":"你是在擔心救贖者大人大人嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저는 그 분의 성녀입니다. 구원자님의 안위를 걱정하는 건 당연한 일이지요.","JPN":"私はあの方の聖女です。救世主様の安危を心配するのは、当たり前のことです。","ENG":"I am his Saintess. It is natural that I worry about the Savior's safety.","TWN":"我是他的聖女，擔心救贖者大人大人的安危是理所當然的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇다면 루크레시아가 선별되면 그만인 문제입니다.","JPN":"それなら、ルクレシアが選ばれればいいのです。","ENG":"Well, then I guess you can save your concerns by getting selected as his partner.","TWN":"那要是露可蕾西亞被選中，這就不是個問題。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"자신 없으십니까?","JPN":"自信がないのですか？","ENG":"Or do you think you will not be chosen?","TWN":"你沒信心嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"매년 <color=#ffd34c>순정</color>한 남녀 한 쌍을 뽑아, 마을의 풍요를 기원하기 위해 신께 제를 올리는 것입니다.","JPN":"毎年、<color=#ffd34c>無垢</color>な男女を選抜し、村の豊穣を祈りながら祭祀を行うのです。","ENG":"We select a <color=#ffd34c>chaste</color> couple to perform a rite, praying to the gods for the prosperity of the village.","TWN":"每年選出一對<color=#ffd34c>純真的</color>男女，向神祈求村莊的豐收。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>불순한 마음</color>으로 순정을 자처하는 꼴이 퍽이나 우습다만.","JPN":"<color=#ffd34c>不純な心</color>で無垢を自称する様はなかなか面白いが。","ENG":"It certainly is amusing how you claim to be chaste while harboring such <color=#ffd34c>impure thoughts</color>.","TWN":"<color=#ffd34c>明明有一顆黑心</color>，卻裝得很純情的樣子，真是好笑。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"유감이군, 루크레시아. 네 알량한 바람을 이루기에는 조금 <color=#ffd34c>늦은 것 같구나</color>.","JPN":"残念だったな、ルクレシア。貴様のつまらない願いを叶えるには少々<color=#ffd34c>遅かったようだ</color>。","ENG":"However, Lucrecia, it seems you are <color=#ffd34c>too late</color> to fulfill your trifling desires.","TWN":"真是可惜， 露可蕾西亞，你卑微的心願<color=#ffd34c>這麼晚才實現</color>。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"우문이로군요. 제국의 성녀가 고작 변방마을의 일을 신경쓰다니요.","JPN":"愚問ですね。帝国の聖女が、たかが辺境の村のことを気にするなんて。","ENG":"A pointless question. As the Saintess of the Empire, there is no need for me to dwell on the matters of a remote village.","TWN":"真是愚蠢的問題。帝國的聖女才不會擔心偏遠村莊的事。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};